FEW_SHOT_GEN_PROMPT = """You are generating training examples for a language model.

Task: {task_description}

Here are two seed examples:
{seed_examples}

Generate {n} additional diverse examples in the same format.
Vary the: phrasing, domain vocabulary, edge cases, and complexity.
Output as a JSON array: [{{"input": "...", "output": "..."}}]"""

def generate_few_shot_examples(
    task_description: str,
    seeds: list[dict],
    n: int = 10,
) -> list[dict]:
    seeds_str = "\n".join(
        f"Input: {s['input']}\nOutput: {s['output']}" for s in seeds
    )
    prompt = FEW_SHOT_GEN_PROMPT.format(
        task_description=task_description,
        seed_examples=seeds_str,
        n=n,
    )
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = response.content[0].text.strip()
    # Strip markdown fences if present
    if raw.startswith("```"):
        raw = raw.split("\n", 1)[1].rsplit("```", 1)[0]
    return json.loads(raw)
